// VALIDACIÓN DE PARÁMETROS - subflujo-tramita-cupon
const input = $input.first().json;

const grupo = input.grupo ? String(input.grupo).trim() : null;
const orden = input.orden ? String(input.orden).trim() : null;
const cuotas = input.cuotas ? String(input.cuotas).trim() : null;
const nombre = input.nombre ? String(input.nombre).trim() : null;

const errores = [];

if (!grupo) errores.push('El parámetro grupo es obligatorio');
if (!orden) errores.push('El parámetro orden es obligatorio');
if (!nombre) errores.push('El parámetro nombre es obligatorio');
if (!cuotas) {
  errores.push('El parámetro cuotas es obligatorio');
} else if (isNaN(Number(cuotas)) || Number(cuotas) <= 0) {
  errores.push('El parámetro cuotas debe ser un número positivo');
}

if (errores.length > 0) {
  return [{ json: { success: false, errores, datos_recibidos: input } }];
}

return [{ json: { success: true, grupo, orden, cuotas, nombre } }];

const input = $('validar-formato').first().json;
return [{
  json: {
    success: true,
    mensaje: `Solicitud de cupón registrada para ${input.nombre} (Grupo ${input.grupo} - Orden ${input.orden}). Recibirás el cupón en 24-48 hs hábiles.`,
    grupo: input.grupo,
    orden: input.orden,
    cuotas: input.cuotas,
    nombre: input.nombre
  }
}];

const input = $('validar-formato').first().json;
return [{
  json: {
    success: false,
    mensaje: 'No se pudo procesar la solicitud de cupón por datos incompletos.',
    errores: input.errores || []
  }
}];
